import json
import hashlib
import redis
from config import REDIS_URL, CACHE_TTL


class RedisCache:
    def __init__(self, url: str = REDIS_URL, max_connections: int = 20):
        self.pool = redis.BlockingConnectionPool.from_url(
            url, max_connections=max_connections, timeout=5
        )
        self.client = redis.Redis(connection_pool=self.pool)
        self.ttl = CACHE_TTL

    def get(self, key: str):
        data = self.client.get(key)
        return json.loads(data) if data else None

    def set(self, key: str, value, ttl: int = None):
        self.client.setex(key, ttl or self.ttl, json.dumps(value))

    def make_key(self, prefix: str, data: dict) -> str:
        raw = json.dumps(data, sort_keys=True)
        h = hashlib.sha256(raw.encode()).hexdigest()[:16]
        return f"{prefix}:{h}"

    def ping(self) -> bool:
        try:
            return self.client.ping()
        except redis.ConnectionError:
            return False
